import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is depreciation?", a: "Depreciation is the process of spreading an asset's cost over its useful life as the asset loses value." },
  { q: "What is straight-line depreciation?", a: "Straight-line depreciation subtracts the same amount every year: asset cost minus salvage value divided by useful life." },
  { q: "What is declining balance depreciation?", a: "Declining balance depreciation applies a fixed rate to the remaining book value, so more depreciation is recorded earlier." },
  { q: "How do you calculate salvage value?", a: "Salvage value is the estimated remaining value of an asset at the end of its useful life." },
  { q: "How does depreciation affect taxes?", a: "Depreciation can reduce taxable business income when the asset is eligible and the method follows tax rules." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

type DepMethod = "Straight-Line" | "Double Declining Balance" | "Sum of Years Digits";
type Row = { year: number; depreciation: number; accumulated: number; book: number };

function schedule(cost: number, salvage: number, life: number, method: DepMethod): Row[] {
  const rows: Row[] = [];
  let book = cost;
  let accumulated = 0;
  const base = Math.max(0, cost - salvage);
  const sumYears = life * (life + 1) / 2;
  for (let year = 1; year <= life; year++) {
    let depreciation = 0;
    if (method === "Straight-Line") depreciation = base / life;
    if (method === "Double Declining Balance") depreciation = Math.min(book * (2 / life), Math.max(0, book - salvage));
    if (method === "Sum of Years Digits") depreciation = base * ((life - year + 1) / sumYears);
    depreciation = Math.max(0, Math.min(depreciation, book - salvage));
    accumulated += depreciation;
    book -= depreciation;
    rows.push({ year, depreciation, accumulated, book });
  }
  return rows;
}

export default function DepreciationCalculator() {
  useCurrencyVersion();
  const [cost, setCost] = useState(50000);
  const [salvage, setSalvage] = useState(5000);
  const [life, setLife] = useState(5);
  const [method, setMethod] = useState<DepMethod>("Straight-Line");
  const rows = useMemo(() => schedule(cost, salvage, Math.max(1, Math.floor(life)), method), [cost, salvage, life, method]);
  const totalDepreciation = rows.reduce((sum, row) => sum + row.depreciation, 0);
  const exampleSL = schedule(50000, 5000, 5, "Straight-Line");
  const exampleDDB = schedule(50000, 5000, 5, "Double Declining Balance");
  const exampleSYD = schedule(50000, 5000, 5, "Sum of Years Digits");

  return (
    <>
      <SEOHead title="Free Depreciation Calculator Online - Calculate Asset Depreciation Instantly | CalcHive" description="Free online depreciation calculator. Calculate straight-line, declining balance and sum of years digits depreciation with full schedule for any asset instantly. 100% free, no signup required." canonical="/depreciation-calculator" keywords="free depreciation calculator, straight line depreciation calculator free, asset depreciation calculator free online, declining balance depreciation calculator free, vehicle depreciation calculator free" category="Financial Calculators" breadcrumbName="Free Depreciation Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Depreciation Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate asset depreciation with straight-line, double declining balance, or sum of years digits methods.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Asset cost</label><input type="number" value={cost} onChange={(e) => setCost(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Salvage value</label><input type="number" value={salvage} onChange={(e) => setSalvage(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Useful life years</label><input type="number" value={life} onChange={(e) => setLife(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Depreciation method</label><select value={method} onChange={(e) => setMethod(e.target.value as DepMethod)} className={inputClass}><option>Straight-Line</option><option>Double Declining Balance</option><option>Sum of Years Digits</option></select></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Total Depreciation</p><p className="text-5xl sm:text-6xl font-black text-white">{money(totalDepreciation)}</p></div>
          <div className="overflow-x-auto mt-5"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><thead className="bg-muted/60"><tr>{["Year", "Annual Depreciation", "Accumulated Depreciation", "Book Value"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((row) => <tr key={row.year}><td className="py-2.5 px-3 font-semibold">{row.year}</td><td className="py-2.5 px-3">{money(row.depreciation)}</td><td className="py-2.5 px-3">{money(row.accumulated)}</td><td className="py-2.5 px-3">{money(row.book)}</td></tr>)}</tbody></table></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Asset Depreciation for Free</h2><p className="text-muted-foreground leading-relaxed">Enter asset cost, salvage value, useful life, and a method to create a full depreciation schedule.</p>
          <h2 className="text-2xl font-bold text-foreground">Straight-Line vs Declining Balance vs Sum of Years Digits</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Depreciation Methods on $50,000 Asset - 5 Year Life - $5,000 Salvage</caption><thead className="bg-muted/60"><tr>{["Year", "Straight-Line", "Double Declining Balance", "Sum of Years Digits", "Book Value (SL)"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{exampleSL.map((row, index) => <tr key={row.year}><td className="py-2.5 px-3 font-semibold">{row.year}</td><td className="py-2.5 px-3">{money(row.depreciation)}</td><td className="py-2.5 px-3">{money(exampleDDB[index].depreciation)}</td><td className="py-2.5 px-3">{money(exampleSYD[index].depreciation)}</td><td className="py-2.5 px-3">{money(row.book)}</td></tr>)}<tr><td className="py-2.5 px-3 font-semibold">Totals</td><td className="py-2.5 px-3">{money(45000)}</td><td className="py-2.5 px-3">{money(45000)}</td><td className="py-2.5 px-3">{money(45000)}</td><td className="py-2.5 px-3">{money(5000)}</td></tr></tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Business and Vehicle Depreciation Tool for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this asset depreciation calculator for vehicles, equipment, business assets, and classroom examples.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/depreciation-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


